// Calculate basic lead score
const contact = $('HubSpot Contact Created').first().json;
const enrichment = $('Clearbit Company Enrichment').first().json;
const criteria = $json;

// Base score
let score = 0;

// Company size scoring
const employees = enrichment?.company?.metrics?.employees || 0;
let sizeCategory = 'startup';
if (employees > 1000) sizeCategory = 'large';
else if (employees > 100) sizeCategory = 'medium';
else if (employees > 10) sizeCategory = 'small';

score += criteria.company_size_weights[sizeCategory] || 0;

// Industry scoring
const industry = enrichment?.company?.category?.industry || '';
if (criteria.target_industries.some(target => industry.toLowerCase().includes(target.toLowerCase()))) {
  score += 20;
}

// Role/title scoring
const title = contact.properties?.jobtitle?.toLowerCase() || '';
let roleScore = 3; // default
for (const [role, weight] of Object.entries(criteria.role_weights)) {
  if (title.includes(role)) {
    roleScore = weight;
    break;
  }
}
score += roleScore;

// Funding bonus (if available)
if (enrichment?.company?.metrics?.raised) {
  score += 15;
}

return {
  contact_data: contact,
  enrichment_data: enrichment,
  basic_score: score,
  size_category: sizeCategory,
  industry_match: criteria.target_industries.some(target => industry.toLowerCase().includes(target.toLowerCase()))
};

